  // Try to fold (X == C1) || ((X & Mask) == C2) into a range check.
  if (!IsLogical && !IsAnd && PredL == ICmpInst::ICMP_EQ && PredR == ICmpInst::ICMP_EQ) {
    Value *X = nullptr;
    const APInt *C_simple = nullptr, *C_masked = nullptr, *Mask = nullptr;
    Value *And = nullptr;
    // Determine which side is masked equality.
    Value *TmpX;
    const APInt *TmpMask;
    if (match(LHS0, m_And(m_Value(TmpX), m_APInt(TmpMask))) && TmpX == RHS0) {
      X = TmpX;
      Mask = TmpMask;
      C_masked = LHSC;
      C_simple = RHSC;
      And = LHS0;
    } else if (match(RHS0, m_And(m_Value(TmpX), m_APInt(TmpMask))) && TmpX == LHS0) {
      X = TmpX;
      Mask = TmpMask;
      C_masked = RHSC;
      C_simple = LHSC;
      And = RHS0;
    }
    if (X && Mask && C_masked && C_simple) {
      // If the 'and' has multiple uses, folding might increase instruction count.
      if (And && !And->hasOneUse())
        return nullptr;
      // Mask must have trailing zeros.
      unsigned TrailingZeros = Mask->countTrailingZeros();
      if (TrailingZeros > 0) {
        // Check that C_masked is aligned: (*C_masked & ~*Mask) == 0
        if ((*C_masked & ~*Mask) == 0) {
          // Compute range for masked equality: [C_masked, C_masked + (1 << TrailingZeros))
          APInt Size = APInt(Mask->getBitWidth(), 1).shl(TrailingZeros);
          ConstantRange MaskedRange(*C_masked, *C_masked + Size);
          ConstantRange SimpleRange(*C_simple, *C_simple + 1);
          // Union
          auto Union = SimpleRange.exactUnionWith(MaskedRange);
          if (Union) {
            // Convert union to range check.
            CmpInst::Predicate NewPred;
            APInt NewC, Offset;
            Union->getEquivalentICmp(NewPred, NewC, Offset);
            Value *NewV = X;
            if (Offset != 0)
              NewV = Builder.CreateAdd(NewV, ConstantInt::get(X->getType(), Offset));
            return Builder.CreateICmp(NewPred, NewV, ConstantInt::get(X->getType(), NewC));
          }
        }
      }
    }
  }
